#include "qp/execution/fill.hpp"
#include <cmath>
namespace qp::execution { Result<void> Fill::validate() const { if(order_id.value==0) return Err(Error{ErrorCode::InvalidArgument,"fill order id must be non-zero"}); if(symbol.empty()) return Err(Error{ErrorCode::InvalidArgument,"fill symbol empty"}); if(!quantity.is_positive()) return Err(Error{ErrorCode::InvalidArgument,"fill quantity must be positive"}); if(!price.is_positive()) return Err(Error{ErrorCode::InvalidArgument,"fill price must be positive"}); if(!std::isfinite(commission) || commission<0.0) return Err(Error{ErrorCode::InvalidArgument,"fill commission must be finite and non-negative"}); if(!std::isfinite(slippage) || slippage<0.0) return Err(Error{ErrorCode::InvalidArgument,"fill slippage must be finite and non-negative"}); return Ok(); } }
